pragma solidity ^0.8.26;

contract UUPSProxy {
    bytes32 private constant IMPLEMENTATION_SLOT = [[SLOT impl_slot]];

    constructor(address _implementation) {
        bytes32 slot = IMPLEMENTATION_SLOT;
        assembly { sstore(slot, _implementation) }
    }

    fallback() external payable {
        bytes32 slot = IMPLEMENTATION_SLOT;
        assembly {
            let impl := sload(slot)
            calldatacopy(0, 0, calldatasize())
            let ok := [[SLOT delegate_call]]
            returndatacopy(0, 0, returndatasize())
            switch ok
            case 0 { revert(0, returndatasize()) }
            default { return(0, returndatasize()) }
        }
    }

    receive() external payable {}
}

contract CounterV1 {
    bytes32 internal constant IMPLEMENTATION_SLOT = bytes32(uint256(keccak256('eip1967.proxy.implementation')) - 1);
    uint256 public count;
    error Unauthorized();

    function increment() external { count += 1; }

    function upgradeToAndCall(address newImpl, bytes calldata data) external {
        bytes32 slot = IMPLEMENTATION_SLOT;
        address current;
        assembly { current := sload(slot) }
        if ([[SLOT init_check]]) revert Unauthorized();
        assembly { sstore(slot, newImpl) }
        if (data.length > 0) {
            (bool ok, ) = newImpl.delegatecall(data);
            require(ok, "init fail");
        }
    }
}

contract CounterV2 {
    bytes32 internal constant IMPLEMENTATION_SLOT = bytes32(uint256(keccak256('eip1967.proxy.implementation')) - 1);
    uint256 public count;
    error Unauthorized();

    function increment() external { count += 10; }

    function upgradeToAndCall(address newImpl, bytes calldata data) external {
        bytes32 slot = IMPLEMENTATION_SLOT;
        address current;
        assembly { current := sload(slot) }
        if (current == address(0)) revert Unauthorized();
        assembly { sstore(slot, newImpl) }
        if (data.length > 0) {
            (bool ok, ) = newImpl.delegatecall(data);
            require(ok, "init fail");
        }
    }
}
